INSERT INTO `text_contents` (`text_content_id`, `lesson_id`, `body`, `word_count`, `reading_time`, `created_at`) VALUES
  ('cc0e8400-e29b-41d4-a716-446655440701', 'aa0e8400-e29b-41d4-a716-446655440502', '<h2>Что такое инфляция?</h2><p>Инфляция — это устойчивое повышение общего уровня цен на товары и услуги...</p><h3>Виды инфляции</h3><ul><li>Умеренная (до 10% в год)</li><li>Галопирующая (10-50%)</li><li>Гиперинфляция (более 50%)</li></ul>', 450, 3, '2026-01-20 10:05:00.000'),
  ('cc0e8400-e29b-41d4-a716-446655440702', 'aa0e8400-e29b-41d4-a716-446655440506', '<h2>Принципы диверсификации</h2><p>«Не кладите все яйца в одну корзину» — золотое правило инвестора...</p><h3>Уровни диверсификации</h3><ol><li>По классам активов</li><li>По отраслям</li><li>По географии</li><li>По валютам</li></ol>', 380, 2, '2026-02-01 12:05:00.000');

